function solve(grid, k) {
    const m = grid.length;
    const n = grid[0].length;
    const teleportMap = Array.from({ length: m }, () => Array(n).fill().map(() => []));
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            const val = grid[i][j];
            for (let x = 0; x < m; x++) {
                for (let y = 0; y < n; y++) {
                    if (grid[x][y] <= val) {
                        teleportMap[i][j].push([x, y]);
                    }
                }
            }
        }
    }

    const dist = Array(m).fill(null).map(() => Array(n).fill(null).map(() => Array(k + 1).fill(Infinity)));
    dist[0][0][0] = 0;

    class PriorityQueue {
        constructor() {
            this.heap = [];
        }
        push(value) {
            this.heap.push(value);
            this.heapifyUp(this.heap.length - 1);
        }
        pop() {
            if (this.heap.length === 0) return null;
            const min = this.heap[0];
            this.heap[0] = this.heap.pop();
            this.heapifyDown(0);
            return min;
        }
        heapifyUp(index) {
            while (index > 0) {
                const parentIndex = Math.floor((index - 1) / 2);
                if (this.heap[index][0] < this.heap[parentIndex][0]) {
                    [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
                    index = parentIndex;
                } else {
                    break;
                }
            }
        }
        heapifyDown(index) {
            const length = this.heap.length;
            while (index < length) {
                const leftChildIndex = 2 * index + 1;
                const rightChildIndex = 2 * index + 2;
                let smallestIndex = index;
                if (leftChildIndex < length && this.heap[leftChildIndex][0] < this.heap[smallestIndex][0]) {
                    smallestIndex = leftChildIndex;
                }
                if (rightChildIndex < length && this.heap[rightChildIndex][0] < this.heap[smallestIndex][0]) {
                    smallestIndex = rightChildIndex;
                }
                if (smallestIndex !== index) {
                    [this.heap[index], this.heap[smallestIndex]] = [this.heap[smallestIndex], this.heap[index]];
                    index = smallestIndex;
                } else {
                    break;
                }
            }
        }
        isEmpty() {
            return this.heap.length === 0;
        }
    }

    const pqInstance = new PriorityQueue();
    pqInstance.push([0, 0, 0, 0]);

    while (!pqInstance.isEmpty()) {
        const [cost, i, j, t] = pqInstance.pop();

        if (i === m - 1 && j === n - 1) {
            return cost;
        }

        if (cost > dist[i][j][t]) {
            continue;
        }

        // Regular moves
        if (j + 1 < n) {
            const newCost = cost + grid[i][j + 1];
            if (newCost < dist[i][j + 1][t]) {
                dist[i][j + 1][t] = newCost;
                pqInstance.push([newCost, i, j + 1, t]);
            }
        }
        if (i + 1 < m) {
            const newCost = cost + grid[i + 1][j];
            if (newCost < dist[i + 1][j][t]) {
                dist[i + 1][j][t] = newCost;
                pqInstance.push([newCost, i + 1, j, t]);
            }
        }

        // Teleport moves
        if (t < k) {
            for (const [x, y] of teleportMap[i][j]) {
                const newT = t + 1;
                if (cost < dist[x][y][newT]) {
                    dist[x][y][newT] = cost;
                    pqInstance.push([cost, x, y, newT]);
                }
            }
        }
    }

    return -1;
}

